class Admin_Model_Cosmetic extends Admin_Model_Base_Cosmetic
{
    public static function saveUserCosmetics($dayId, $userId, $productName) {
        $cosmetic = new Admin_Model_Cosmetic();
        $cosmetic->Day_ID = $dayId;
        $cosmetic->User_ID = $userId;
        $cosmetic->Name = trim($productName);
        $cosmetic->save();

    }
    public static function deleteCosmeticsForDay($dayId, $userId) {
        Doctrine_Query::create()
            ->delete('Admin_Model_Cosmetic')
            ->where('Day_ID = ?', $dayId)
            ->andWhere('User_ID = ?', $userId)
            ->execute();
    }

    public static function getCosmeticsForDay($dayId, $userId) {
        $cosmetics = Doctrine_Query::create()
            ->from('Admin_Model_Cosmetic object')
            ->where('object.Day_ID = ?', $dayId)
            ->andWhere('object.User_ID = ?', $userId)
            ->execute();

        return $cosmetics ?? null;
    }


}